Here's how to test `DataFetcher` with proper timeout/cancellation handling:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(() =>
        {
            cts.Cancel(); // simulate cancel during request
            cts.Token.ThrowIfCancellationRequested();
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CooperativeTimeout_IsCancelledByTestContext()
    {
        // TestContext.CancellationToken fires when [Timeout] expires.
        // Pass it into FetchAsync so slow calls get cancelled automatically.
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast response")
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast response", result);
    }

    // Minimal fake handler — no mocking framework needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpResponseMessage> _factory;

        public FakeHandler(HttpResponseMessage response) : this(() => response) { }

        public FakeHandler(Func<HttpResponseMessage> factory) => _factory = factory;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_factory());
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout] + _testContext.CancellationToken` | Cooperative timeout — the token fires when the timeout expires, cancelling the async call cleanly |
| `Assert.ThrowsExactlyAsync<T>` | Modern replacement for `[ExpectedException]`; lets you inspect the exception |
| `FakeHandler` | Controls `HttpClient` without mocking frameworks; checks `CancellationToken` |
| Sealed test class + sealed handler | Performance and design clarity |

The critical insight: **always pass `_testContext.CancellationToken`** to your async code under test. Without it, `[Timeout]` can only abort the test thread — with it, the operation itself gets cancelled cooperatively.
